SELECT id, title, content, answer, category, difficulty, direction,
       view_count, favorite_count, is_deleted, created_at, updated_at
FROM question

    is_deleted = 0

        AND category = #{category}


        AND difficulty = #{difficulty}


        AND direction = #{direction}


        AND (title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY created_at DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM question

    is_deleted = 0

        AND category = #{category}


        AND difficulty = #{difficulty}


        AND direction = #{direction}


        AND (title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))

SELECT id, title, content, answer, category, difficulty, direction, view_count, favorite_count, created_at, updated_at FROM question WHERE is_deleted = 0
AND direction = #{direction}
ORDER BY RAND() LIMIT #{limit}

SELECT id, title, content, answer, category, difficulty, direction,
       view_count, favorite_count, created_at, updated_at
FROM question
WHERE is_deleted = 0

    AND direction = #{direction}

AND difficulty = #{difficulty}
ORDER BY RAND()
LIMIT #{limit}

SELECT id, title, content, answer, category, difficulty, direction,
       view_count, favorite_count, created_at, updated_at
FROM question
WHERE is_deleted = 0

    AND direction = #{direction}


    AND id NOT IN

        #{id}


ORDER BY RAND()
LIMIT #{limit}

